<?php
 namespace WPAICG\Chat\Storage\LoggerMethods; if (!defined('ABSPATH')) { exit; } function build_where_clauses_logic( string $conversation_uuid, string $module, ?int $bot_id, ?int $user_id, ?string $session_id ): array { $where_clauses = ["conversation_uuid = %s", "module = %s"]; $params = [$conversation_uuid, $module]; if ($bot_id !== null) { $where_clauses[] = "bot_id = %d"; $params[] = $bot_id; } else { $where_clauses[] = "bot_id IS NULL"; } if ($user_id) { $where_clauses[] = "user_id = %d"; $params[] = $user_id; } else { if (empty($session_id)) { $where_clauses[] = "1=0"; } else { $where_clauses[] = "(user_id IS NULL AND session_id = %s AND is_guest = 1)"; $params[] = $session_id; } } return ['where_sql' => implode(" AND ", $where_clauses), 'params' => $params]; }